if not error_message:
    try:
        timestamp_columns = [
            'eventStartDateTime',
            'eventEndDateTime',
            'IngestionDate',
            'ValidTo',
        ]

        final_view_df = view_df.withColumns({
            col: F.to_timestamp(
                F.from_utc_timestamp(F.col(col), 'Europe/London'),
                "yyyy-MM-dd'T'HH:mm:ss.SSS"
            )
            for col in timestamp_columns
        })

    except Exception as e:
        error_message = f"Error in timestamp conversion: {str(e)[:800]}"
        end_exec_time = datetime.now()
        print(error_message)
